import{_ as a,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"66. Ceremonial Leave","description":"","frontmatter":{"title":"66. Ceremonial Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","ceremonial-leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/66-ceremonial-leave.md","filePath":"ebas/biomedical-engineers/leave/66-ceremonial-leave.md"}'),i={name:"ebas/biomedical-engineers/leave/66-ceremonial-leave.md"};function n(l,e,s,c,p,m){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_66-ceremonial-leave" tabindex="-1">66. Ceremonial Leave <a class="header-anchor" href="#_66-ceremonial-leave" aria-label="Permalink to &quot;66. Ceremonial Leave&quot;">​</a></h1><p><strong>66.1</strong> An Employee who is legitimately required by Aboriginal and/or Torres Strait Islander tradition to be absent from work for ceremonial purposes will be entitled to up to ten working days&#39; unpaid leave in any one year, with the approval of the Employer.</p><p><strong>66.2</strong> Where an Employer receives a request to substitute a public holiday in accordance with <a href="/eba/ebas/biomedical-engineers/leave/50-public-holidays.html">clause 50.4</a> of this Agreement for a day during NAIDOC week, the Employer will consider all the circumstances including:</p><p><strong>(a)</strong> any reason identified by the Employee with respect to the request; and</p><p><strong>(b)</strong> the operational requirements of the Employer.</p><p><strong>66.3</strong> An Employer will not unreasonably refuse a request to substitute a public holiday under this subclause.</p>',6)])])}const h=a(i,[["render",n]]);export{u as __pageData,h as default};
